var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"요즘 같은 시대에도 여전히 종이책 읽는 걸 좋아하는군, 비블리데.","JPN":"このような時代になっても、相変わらず紙の本の方を好むのだね、ビブリデ。","ENG":"I see you are still reading those paper books, Biblide.","TWN":"現在竟然還有人喜歡讀紙本書呢，布莉黛。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"하긴, 자네와 베네딕트는 어렸을 때부터 책을 참 좋아했지.","JPN":"まあ、君とベネディクトは小さい頃から本が大好きだったからな。","ENG":"Well, you and Benedict practically buried yourselves in books since you were children.","TWN":"也是，你和本尼迪克特從小就很喜歡看書。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"두 사람이 경쟁하듯, 고아원에 있던 책이란 책은 모조리 읽어서 곤란할 정도였어. 허허.","JPN":"二人が競争するように、孤児院にある本をすべて読んでしまったのには困ったものだ。ホッホッ。","ENG":"It was as if you two were trying to see who could read the most books, and in the end, I was the one in trouble because you both read every book there is at the orphanage. *Chuckle*","TWN":"二個人好像在比賽一樣，把孤兒院裡只要像書的東西全都翻出來看，真是令人傷腦筋呢，呵呵～"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"지금도 그 때만 생각하면…….","JPN":"今でもあの時のことを考えると……","ENG":"When I think back on those times─","TWN":"現在回想起來……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해드리죠, 예하.","JPN":"喜んで訂正いたします、猊下。","ENG":"I would be more than happy to rephrase, your Eminence.","TWN":"我要更正一下，主教。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"예하께서 곤란하셨던 까닭은 벽장 속에 숨겨 두신 성인 잡지도 찾아내서 읽었기 때문으로 알고 있습니다만.","JPN":"猊下がお困りになった理由は、押し入れに隠されたアダルト雑誌をも見つけて読んでしまったためです。","ENG":"Your Eminence, the only reason you were in trouble was because I discovered, and read, the naughty magazine you had hidden in the closet.","TWN":"據我所知，主教之所以會傷腦筋，是因為藏在櫃子裡的成人雜誌被發現。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"흠, 크흠. 그 잡지는 내 것이 아니래도.","JPN":"ふむ、こほん。あの雑誌は私のものではないと言ったではないか。","ENG":"Hmm... Ahem! Did I not say that the magazine is not mine?","TWN":"咳咳，就說那本雜誌不是我的。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그, 그래서 도서관을 담당하는 일은 할 만하고?","JPN":"そ、それで図書館の仕事の方はどうだね？","ENG":"A-anyway, how is your work as a librarian fairing?","TWN":"那個，在圖書館工作還習慣吧？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"주님께서는 모든 어린 양들에게 재능을 부여하시고 그에 걸맞은 결실을 맺길 바라십니다.","JPN":"主はすべての子羊に才能を与え、それにふさわしい実りをお望みです。","ENG":"The Lord has given all of his lambs talents, and desires for them to bear fruit.","TWN":"天主有給每隻小羊才幹，並且期待能夠結果子。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그리고 저의 재능에 걸맞은 일은 얌전히 이 서고에서 후세에 전할 지식을 보존하는 것이겠죠.","JPN":"そして私の才能にふさわしい仕事とは、大人しくこの書庫で後世に伝える知識を保存することでしょう。","ENG":"With my talent, I intend to quietly preserve the knowledge that I will pass on to future generations in this library.","TWN":"而符合我才幹的工作，就是老實待在圖書館裡，替下一代保管好這些寶貴的知識。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"허허……. 나는 아직 아무 말도 안 했다만?","JPN":"ホッホッ……私はまだ何も言っていないが？","ENG":"*Chuckle* But I have not said anything yet?","TWN":"呵呵……我什麼都還沒說呢？"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"천사는 가까이…… 하지만 사탄은 더 가까이……","JPN":"天使と親しく……だが悪魔にはもっと親しく……","ENG":"Keep angels close... but the devil closer...","TWN":"離天使近一點……離撒旦更近一點……"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"성황청 대침식전 전문 기관, 기적심의회. 세간에서 부르는 속칭은 <color=#ffd34c>주님의 미친개들</color>.\xA0","JPN":"聖皇庁の対侵食戦専門機関、奇跡審議会。世間での俗称は<color=#ffd34c>主の狂犬たち</color>。\xA0","ENG":"The Miracle Investigation Council, Holy Curia's Anti-Corruption Institution. Or, as some people call it, the <color=#ffd34c>Mad Dogs of the Lord</color>.\xA0","TWN":"聖皇廳侵蝕戰專責機關 奇蹟議會，世人俗稱為<color=#ffd34c>天主的走狗</color>。\xA0"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 의장이신 요한 추기경께서 이런 낡은 서고를 찾아주시니 몸 둘 바를 모르겠군요.","JPN":"その議長であるヨハン枢機卿猊下に、このような古い書庫をお訪ねいただき光栄です。","ENG":"It is an honor that you, Cardinal Johan, Chairman of Miracle Investigation Council, personally pays me a visit at this old library.","TWN":"議長約翰樞機主教突然大駕光臨，真是受寵若驚呢。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"크흠. 불경한 이단들이나 부르는 별명 아닌가. 섭섭하구만.","JPN":"こほん。それは不敬な異端者たちが呼ぶ名ではないか。寂しいことを言う。","ENG":"Ahem... Is that not what those profane heretics refer to us as? I am truly disappointed.","TWN":"咳咳，異端才會那麼稱呼不是嗎？真令人難過。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"우리 심의회도 대외적인 이미지 쇄신을 위해 노력 중이네.","JPN":"審議会も対外的なイメージ刷新のために努力しているんだ。","ENG":"Although, the Investigation Council is working hard to improve our public image.","TWN":"議會已經努力在洗刷外界對我們的刻板印象。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자네가 없는 사이, 귀여운 후배들도 잔뜩 생겼지.","JPN":"君がいない間に、可愛い後輩たちもたくさん入ってきたんだぞ。","ENG":"Also, while you were away, a lot of cute junior members have joined.","TWN":"你不在的這段時間，議會裡也是可愛的新人輩出呢。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CARDINAL_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"특히 루퍼 양은 자네 어릴 때를 쏙 빼닮았어.\xA0","JPN":"特にルーパー君は君の小さい頃にそっくりだ。\xA0","ENG":"Miss Looper, in particular, reminds me of you as a child.\xA0","TWN":"尤其是洛珀，她和你小時候簡直是一個模子刻出來的。"},"stage":{"bg":"CHURCH","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};